#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t X, Y, Z; scanf("%" PRId64 " %" PRId64 " %" PRId64, &X, &Y, &Z);
        int64_t breaks = (X-1)/3; // integer division, works for X>=1
        int64_t total = X*Y + breaks*Z;
        printf("%" PRId64 "\n", total);
    }
    return 0;
}

